import{_ as s,o as t,c as e,a4 as i}from"./chunks/framework.BDOgl-CJ.js";const k=JSON.parse('{"title":"Web Server 部署到 10.17.0.22 — 问题与解决报告","description":"","frontmatter":{},"headers":[],"relativePath":"artifacts/deployment_report.md","filePath":"artifacts/deployment_report.md","lastUpdated":1777290866000}'),n={name:"artifacts/deployment_report.md"};function o(r,a,l,d,h,p){return t(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="web-server-部署到-10-17-0-22-—-问题与解决报告" tabindex="-1">Web Server 部署到 10.17.0.22 — 问题与解决报告 <a class="header-anchor" href="#web-server-部署到-10-17-0-22-—-问题与解决报告" aria-label="Permalink to &quot;Web Server 部署到 10.17.0.22 — 问题与解决报告&quot;">​</a></h1><h2 id="部署结果" tabindex="-1">部署结果 <a class="header-anchor" href="#部署结果" aria-label="Permalink to &quot;部署结果&quot;">​</a></h2><p>✅ <strong>服务已成功部署在 10.17.0.22 上</strong>，Docker 容器 <code>web_server</code> 正常运行，Caddy 在容器内 <code>:8080</code> 端口服务静态文件，映射到宿主机 <code>:8888</code>。</p><hr><h2 id="问题一-harbor-镜像拉取失败" tabindex="-1">问题一：Harbor 镜像拉取失败 <a class="header-anchor" href="#问题一-harbor-镜像拉取失败" aria-label="Permalink to &quot;问题一：Harbor 镜像拉取失败&quot;">​</a></h2><h3 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Error response from daemon: failed to resolve reference &quot;docker.anyverse.work/library/web_server:latest&quot;:</span></span>
<span class="line"><span>Head &quot;https://docker.anyverse.work/v2/library/web_server/manifests/latest&quot;:</span></span>
<span class="line"><span>dial tcp 10.17.1.25:443: connect: connection refused</span></span></code></pre></div><h3 id="根因" tabindex="-1">根因 <a class="header-anchor" href="#根因" aria-label="Permalink to &quot;根因&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>状态</th></tr></thead><tbody><tr><td>Harbor 服务器 <code>docker.anyverse.work</code> (10.17.1.25) 的 <strong>443 端口 (HTTPS)</strong></td><td>❌ 不可达</td></tr><tr><td>Harbor 服务器的 <strong>80 端口 (HTTP)</strong></td><td>✅ 可达</td></tr></tbody></table><p>Docker 默认通过 <strong>HTTPS (443)</strong> 拉取镜像，但你们的 Harbor 实例<strong>只开放了 HTTP (80)</strong>。Docker 遇到非 HTTPS 的 Registry 时会直接拒绝拉取。</p><h3 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h3><p>在 22 机器的 <code>/etc/docker/daemon.json</code> 中添加 <code>insecure-registries</code> 配置，告诉 Docker 允许通过 HTTP 访问该 Registry：</p><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   &quot;log-driver&quot;: &quot;json-file&quot;,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   &quot;log-opts&quot;: { &quot;max-size&quot;: &quot;10m&quot;, &quot;max-file&quot;: &quot;3&quot; },</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">-  &quot;default-address-pools&quot;: [{&quot;base&quot;:&quot;10.0.0.0/8&quot;,&quot;size&quot;:24}]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+  &quot;default-address-pools&quot;: [{&quot;base&quot;:&quot;10.0.0.0/8&quot;,&quot;size&quot;:24}],</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+  &quot;insecure-registries&quot;: [&quot;docker.anyverse.work&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>然后重启 Docker：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker</span></span></code></pre></div><p>之后还需要登录 Harbor：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker.anyverse.work</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;robot$library+ci_bot&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;密码&gt;&#39;</span></span></code></pre></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>这是 22 机器特有的问题。如果其他机器也需要拉取 Harbor 镜像，同样需要做这两步配置。</p></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p><code>insecure-registries</code> 意味着镜像传输走的是明文 HTTP，不加密。在内网环境下可以接受，但建议后续给 Harbor 配置 TLS 证书以启用 HTTPS (443)。</p></div><hr><h2 id="问题二-本机浏览器无法访问-http-10-17-0-22-8888" tabindex="-1">问题二：本机浏览器无法访问 <code>http://10.17.0.22:8888</code> <a class="header-anchor" href="#问题二-本机浏览器无法访问-http-10-17-0-22-8888" aria-label="Permalink to &quot;问题二：本机浏览器无法访问 \`http://10.17.0.22:8888\`&quot;">​</a></h2><h3 id="现象-1" tabindex="-1">现象 <a class="header-anchor" href="#现象-1" aria-label="Permalink to &quot;现象&quot;">​</a></h3><p>浏览器访问 <code>http://10.17.0.22:8888</code> 显示无法正常运作。</p><h3 id="根因-1" tabindex="-1">根因 <a class="header-anchor" href="#根因-1" aria-label="Permalink to &quot;根因&quot;">​</a></h3><p>你的 Mac 上配置了 HTTP 代理：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http_proxy=http://127.0.0.1:7897</span></span>
<span class="line"><span>https_proxy=http://127.0.0.1:7897</span></span>
<span class="line"><span>no_proxy=（未设置）</span></span></code></pre></div><p>这是 Clash/ClashX 类代理工具的默认监听端口。由于 <code>no_proxy</code> 未设置，<strong>所有 HTTP 流量</strong>（包括内网 <code>10.17.x.x</code>）都被代理拦截。代理无法正确转发到内网 IP，返回 <code>502 Bad Gateway</code>。</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>服务本身是正常的 — 在 22 机器上 <code>curl localhost:8888</code> 返回 200 OK。</p></div><h3 id="解决方案-二选一" tabindex="-1">解决方案（二选一） <a class="header-anchor" href="#解决方案-二选一" aria-label="Permalink to &quot;解决方案（二选一）&quot;">​</a></h3><h4 id="方案-a-在代理软件中配置直连规则-推荐" tabindex="-1">方案 A：在代理软件中配置直连规则（推荐） <a class="header-anchor" href="#方案-a-在代理软件中配置直连规则-推荐" aria-label="Permalink to &quot;方案 A：在代理软件中配置直连规则（推荐）&quot;">​</a></h4><p>在你的 Clash/ClashX 配置文件中，添加内网 IP 段的直连规则：</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">rules</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 内网地址直连，不走代理</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,10.0.0.0/8,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,172.16.0.0/12,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">IP-CIDR,192.168.0.0/16,DIRECT</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # ... 其他规则</span></span></code></pre></div><p>或者在系统网络设置中配置「忽略这些主机与域的代理设置」，添加：<code>10.17.*</code></p><h4 id="方案-b-ssh-隧道转发-临时方案" tabindex="-1">方案 B：SSH 隧道转发（临时方案） <a class="header-anchor" href="#方案-b-ssh-隧道转发-临时方案" aria-label="Permalink to &quot;方案 B：SSH 隧道转发（临时方案）&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 8888:localhost:8888</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wujie@10.17.0.22</span></span></code></pre></div><p>然后通过 <code>http://localhost:8888</code> 访问。这会绕过所有代理，但需要保持 SSH 隧道运行。</p><hr><h2 id="操作时间线" tabindex="-1">操作时间线 <a class="header-anchor" href="#操作时间线" aria-label="Permalink to &quot;操作时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间</th><th>操作</th></tr></thead><tbody><tr><td>14:12</td><td>克隆 <code>project/grid</code> 分支到 <code>~/anyverse</code>（8081 文件）</td></tr><tr><td>14:13</td><td>首次运行 <code>start_webserver.sh</code> → Harbor 443 拒绝连接</td></tr><tr><td>14:16</td><td>诊断发现 Harbor 80 可达、443 不可达</td></tr><tr><td>14:16</td><td>修改 <code>daemon.json</code> 添加 <code>insecure-registries</code> + 重启 Docker</td></tr><tr><td>14:17</td><td>Docker login Harbor 成功</td></tr><tr><td>14:17</td><td>重新运行脚本 → 镜像拉取成功，容器启动，Caddy 正常服务</td></tr><tr><td>14:18</td><td>发现本机浏览器 502 → 定位到代理问题</td></tr><tr><td>14:20</td><td>SSH 隧道作为临时方案验证 200 OK</td></tr></tbody></table><hr><p>维护者: 基座模型组</p>`,41)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
